      }
    })();

    return () => clearInterval(pollInterval);
  }, []);

  // Login/logout when user changes
  useEffect(() => {
    if (Platform.OS === 'web') return;
    if (!OS) return;
    if (!isInitialized) return;
    if (isUserLoading) return;

    const userId = user?.id;

    if (!userId) {
      if (externalUserId) {
